    page, _ = ExtensionPage.objects.get_or_create(
        slug="trick-regulation",
        defaults={
            "title": "Trick 页面贡献值与投票规则",
            "description": "用于说明 Trick 页面的贡献值、投票权限与审核规则。",
            "content_md": TRICK_REGULATION_CONTENT,
            "access_level": "public",
            "is_enabled": True,
        },
    )
    if not str(page.content_md or "").strip():
        page.content_md = TRICK_REGULATION_CONTENT
    page.title = "Trick 页面贡献值与投票规则"
    page.description = "用于说明 Trick 页面的贡献值、投票权限与审核规则。"
    page.access_level = "public"
    page.is_enabled = True
    page.save()

    section, _ = DocumentPageSection.objects.get_or_create(
        key="trick-regulation",
        defaults={
            "title": "Trick 页面贡献值与投票规则",
            "page": page,
            "display_order": 25,
            "is_visible": True,
        },
    )
    section.title = "Trick 页面贡献值与投票规则"
    section.page = page
    section.display_order = 25
    section.is_visible = True
    section.save()


